import React from 'react';
import { DEMO_MODE } from '../config';

const DemoBanner = () => {
  if (!DEMO_MODE) return null;

  return (
    <div style={{
      background: 'linear-gradient(135deg, #0f172a 0%, #1e293b 50%, #0f172a 100%)',
      color: '#e2e8f0',
      padding: '12px 20px',
      textAlign: 'center',
      fontWeight: '500',
      position: 'sticky',
      top: 0,
      zIndex: 9999,
      borderBottom: '2px solid #8b5cf6',
      boxShadow: '0 4px 20px rgba(0,0,0,0.3)',
      fontSize: '14px',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      gap: '12px',
      flexWrap: 'wrap',
      backdropFilter: 'blur(8px)',
    }}>
      <span style={{
        background: 'linear-gradient(135deg, #8b5cf6, #6d28d9)',
        color: 'white',
        padding: '4px 14px',
        borderRadius: '20px',
        fontSize: '11px',
        fontWeight: '700',
        textTransform: 'uppercase',
        letterSpacing: '0.8px',
        boxShadow: '0 2px 8px rgba(139, 92, 246, 0.4)',
      }}>
        🚀 Demo Mode
      </span>
      <span>🔍 <strong>View-Only</strong> — Explore all features without making changes</span>
      <span style={{
        fontSize: '11px',
        color: '#94a3b8',
        background: 'rgba(148, 163, 184, 0.1)',
        padding: '4px 12px',
        borderRadius: '12px',
      }}>
        admin@csuniversity.com / universityadmin
      </span>
    </div>
  );
};

export default DemoBanner;
